class TrackerService:
    def __init__(self, tasks=None):
        self.tasks = tasks or []

    def add_task(self, task):
        self.tasks.append(task)

    def mark_done(self, title):
        for task in self.tasks:
            if task.title == title:
                task.status = "done"
                return True
        return False

    def count_open_tasks(self):
        count = 0
        for task in self.tasks:
            if task.status != "done":
                count += 1
        return count

